for (vector<int>::const_iterator it = numbers.begin(); it != numbers.end(); it++)
{
    cout << *it; // fine — reading
    // *it = 99;  // ERROR — const_iterator forbids modifying through it
}

#include <iostream>
#include <vector>

using namespace std;

int main()
{
    vector<int> numbers = {1, 2, 3};

    for (vector<int>::reverse_iterator it = numbers.rbegin(); it != numbers.rend(); it++)
    {
        cout << *it << " ";
    }

    return 0;
}

vector<int> numbers = {1, 2, 3};

auto it = numbers.begin();
numbers.push_back(4); // may cause vector to resize (recall vector's growth from the vector topic)

cout << *it; // DANGER — it might now be dangling, pointing at freed memory

